const cfg = $json;
if (cfg.send_hour === null || cfg.send_hour === undefined) {
  console.log('[lembretes-reserva] send_hour não configurado — usando 10h');
  cfg.send_hour = 10;
}
if (cfg.current_hour !== cfg.send_hour) {
  console.log(`[lembretes-reserva] Fora da janela (hora atual=${cfg.current_hour}, enviar=${cfg.send_hour})`);
  return [];
}
return [{ json: cfg }];

const rows = $input.all();
console.log(`[lembretes-reserva] ${rows.length} lembrete(s) para enviar`);
if (!rows || rows.length === 0) return [];
return rows;

const r = $json;
const cfg = $('Buscar Config e Reservas').first().json;
const nome = r.customer_name || 'cliente';
const nomeCapit = nome.charAt(0).toUpperCase() + nome.slice(1);
const addr = cfg.establishment_address || '';
const mapsLink = addr ? '\n🗺️ https://maps.google.com/?q=' + encodeURIComponent(addr) : '';
const addrBlock = addr ? '\n\n📍 *Localização:* ' + addr + mapsLink : '';

// Format date
const [y, m, d] = r.date.toString().split('T')[0].split('-');
const meses = ['','Janeiro','Fevereiro','Março','Abril','Maio','Junho','Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];
const dateStr = parseInt(d) + ' de ' + meses[parseInt(m)];

const time = r.time.substring(0, 5);
const mesa = r.table_number ? 'Mesa ' + r.table_number : '';
const party = r.party_size + (r.party_size === 1 ? ' pessoa' : ' pessoas');

let msg;
if (r.tipo_lembrete === 'amanha') {
  msg = '📅 *Lembrete de reserva, ' + nomeCapit + '!*\n\n'
    + 'Sua reserva é *amanhã* 🌸\n\n'
    + '🗓️ ' + dateStr + ' às ' + time + '\n'
    + '👥 ' + party + '\n'
    + (mesa ? '🪑 ' + mesa + '\n' : '')
    + addrBlock + '\n\n'
    + 'Até amanhã! Se precisar alterar ou cancelar, responda esta mensagem.';
} else {
  msg = '🌸 *Hoje é o dia, ' + nomeCapit + '!*\n\n'
    + 'Sua reserva é *hoje* 🎉\n\n'
    + '🗓️ ' + dateStr + ' às ' + time + '\n'
    + '👥 ' + party + '\n'
    + (mesa ? '🪑 ' + mesa + '\n' : '')
    + addrBlock + '\n\n'
    + 'Te esperamos! Se precisar alterar, responda esta mensagem.';
}

return [{ json: { ...r, msg, cfg } }];

const { customer_phone, msg, cfg } = $json;
const instancia = $env['EVOLUTION_INSTANCE'] || 'default';
const apiKey = cfg.evolution_api_key || $env['EVOLUTION_API_KEY'] || '';
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `http://evolution_api:8080/message/sendText/${instancia}`,
    headers: { 'Content-Type': 'application/json', 'apikey': apiKey },
    body: JSON.stringify({ number: customer_phone, text: msg })
  });
} catch(e) {
  console.log('[lembretes-reserva] Erro ao enviar para', customer_phone, e.message);
}
return [{ json: $json }];
